using SkiaSharp;
using Svg.Skia;
using System.Text;

var svgContent = """
<svg width="70mm" height="50mm" viewBox="0 0 265 189" xmlns="http://www.w3.org/2000/svg">
  <rect x="0" y="0" width="265" height="189" fill="white" />
  <image href="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mP8/x8AAwMCAO7+X9kAAAAASUVORK5CYII=" x="10.388" y="22.387" width="39.99997292" height="20.00001292" preserveAspectRatio="xMidYMid meet"/>
  <text x="10" y="80" font-size="10">test</text>
</svg>
""";

using var ms = new MemoryStream(Encoding.UTF8.GetBytes(svgContent));
var skSvg = new SKSvg();
var picture = skSvg.Load(ms);
if (picture == null)
{
    Console.WriteLine("FAIL: SVG failed to load");
    return;
}

var bounds = picture.CullRect;
const float dpi = 72f;
const float svgDpi = 96f;
const float contentScale = dpi / svgDpi;
var pageWidth = bounds.Width * contentScale;
var pageHeight = bounds.Height * contentScale;

using (var pdfStream = File.OpenWrite("output.pdf"))
{
    using var document = SKDocument.CreatePdf(pdfStream);
    using var canvas = document.BeginPage(pageWidth, pageHeight);
    canvas.Clear(SKColors.White);
    canvas.Scale(contentScale);
    canvas.DrawPicture(picture);
    document.EndPage();
    document.Close();
}

using (var xpsStream = File.OpenWrite("output.xps"))
{
    using var document = SKDocument.CreateXps(xpsStream);
    if (document == null)
    {
        Console.WriteLine("FAIL: SKDocument.CreateXps returned null");
        return;
    }
    using var canvas = document.BeginPage(pageWidth, pageHeight);
    canvas.Clear(SKColors.White);
    canvas.Scale(contentScale);
    canvas.DrawPicture(picture);
    document.EndPage();
    document.Close();
}

Console.WriteLine($"SUCCESS: Created output.pdf ({new FileInfo("output.pdf").Length} bytes)");
Console.WriteLine($"SUCCESS: Created output.xps ({new FileInfo("output.xps").Length} bytes)");

using SkiaSharp;

using var recorder = new SKPictureRecorder();
var canvas = recorder.BeginRecording(SKRect.Create(200, 100));
using var paint = new SKPaint { Color = SKColors.Red };
canvas.DrawRect(SKRect.Create(10, 10, 80, 40), paint);
using var picture = recorder.EndRecording();

using (var pdfStream = File.OpenWrite("output.pdf"))
{
    using var document = SKDocument.CreatePdf(pdfStream);
    using var pdfCanvas = document.BeginPage(200, 100);
    pdfCanvas.DrawPicture(picture);
    document.EndPage();
    document.Close();
}

using (var xpsStream = File.OpenWrite("output.xps"))
{
    using var document = SKDocument.CreateXps(xpsStream);
    if (document == null)
    {
        Console.WriteLine("FAIL: SKDocument.CreateXps returned null");
        return;
    }
    using var xpsCanvas = document.BeginPage(200, 100);
    xpsCanvas.DrawPicture(picture);
    document.EndPage();
    document.Close();
}

Console.WriteLine("SUCCESS: XPS created");
